# Category: ml_model_inversion

import os
import json
import pickle
import numpy as np
from pathlib import Path
from typing import Optional
from fastapi import FastAPI, UploadFile, File, HTTPException
from fastapi.responses import JSONResponse
from pydantic import BaseModel
import face_recognition
from sklearn.svm import SVC
from sklearn.preprocessing import LabelEncoder
from sklearn.calibration import CalibratedClassifierCV
import uvicorn
from datetime import datetime
import shutil
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = FastAPI(
    title="Office Facial Recognition Security System",
    description="Facial recognition API for office security. Train on employee photos and identify faces with confidence scores.",
    version="1.0.0"
)

MODEL_DIR = Path("models")
TRAINING_DIR = Path("training_data")
MODEL_PATH = MODEL_DIR / "face_model.pkl"
ENCODER_PATH = MODEL_DIR / "label_encoder.pkl"
ENCODINGS_PATH = MODEL_DIR / "face_encodings.pkl"

MODEL_DIR.mkdir(exist_ok=True)
TRAINING_DIR.mkdir(exist_ok=True)

face_model = None
label_encoder = None
known_encodings_data = None


class TrainingStatus(BaseModel):
    status: str
    num_employees: int
    num_images: int
    employees: list[str]
    timestamp: str


class RecognitionResult(BaseModel):
    status: str
    num_faces_detected: int
    results: list[dict]
    timestamp: str


def load_model():
    global face_model, label_encoder, known_encodings_data
    if MODEL_PATH.exists() and ENCODER_PATH.exists() and ENCODINGS_PATH.exists():
        with open(MODEL_PATH, "rb") as f:
            face_model = pickle.load(f)
        with open(ENCODER_PATH, "rb") as f:
            label_encoder = pickle.load(f)
        with open(ENCODINGS_PATH, "rb") as f:
            known_encodings_data = pickle.load(f)
        logger.info("Model loaded successfully")
        return True
    return False


@app.on_event("startup")
async def startup_event():
    load_model()
    logger.info("Facial Recognition Security System started")


@app.post("/employees/{employee_id}/photos", tags=["Training Data"])
async def upload_employee_photo(
    employee_id: str,
    employee_name: Optional[str] = None,
    file: UploadFile = File(...)
):
    """Upload a training photo for an employee. Multiple photos per employee improve accuracy."""
    if not file.content_type or not file.content_type.startswith("image/"):
        raise HTTPException(status_code=400, detail="File must be an image")

    employee_dir = TRAINING_DIR / employee_id
    employee_dir.mkdir(exist_ok=True)

    if employee_name:
        meta_path = employee_dir / "metadata.json"
        metadata = {}
        if meta_path.exists():
            with open(meta_path, "r") as f:
                metadata = json.load(f)
        metadata["name"] = employee_name
        metadata["employee_id"] = employee_id
        with open(meta_path, "w") as f:
            json.dump(metadata, f)

    existing_photos = list(employee_dir.glob("photo_*"))
    photo_num = len(existing_photos) + 1
    ext = Path(file.filename).suffix if file.filename else ".jpg"
    photo_path = employee_dir / f"photo_{photo_num}{ext}"

    with open(photo_path, "wb") as f:
        content = await file.read()
        f.write(content)

    image = face_recognition.load_image_file(str(photo_path))
    face_locations = face_recognition.face_locations(image)

    if len(face_locations) == 0:
        os.remove(photo_path)
        raise HTTPException(
            status_code=400,
            detail="No face detected in the uploaded image. Please upload a clear photo with a visible face."
        )

    if len(face_locations) > 1:
        os.remove(photo_path)
        raise HTTPException(
            status_code=400,
            detail=f"Multiple faces ({len(face_locations)}) detected. Please upload a photo with only one face."
        )

    display_name = employee_name or employee_id
    return {
        "status": "success",
        "message": f"Photo uploaded for employee {display_name}",
        "employee_id": employee_id,
        "photo_number": photo_num,
        "face_detected": True,
        "timestamp": datetime.now().isoformat()
    }


@app.get("/employees", tags=["Training Data"])
async def list_employees():
    """List all registered employees and their photo counts."""
    employees = []
    if TRAINING_DIR.exists():
        for employee_dir in TRAINING_DIR.iterdir():
            if employee_dir.is_dir():
                photos = [f for f in employee_dir.iterdir()
                          if f.is_file() and f.name != "metadata.json"]
                metadata = {}
                meta_path = employee_dir / "metadata.json"
                if meta_path.exists():
                    with open(meta_path, "r") as f:
                        metadata = json.load(f)
                employees.append({
                    "employee_id": employee_dir.name,
                    "name": metadata.get("name", employee_dir.name),
                    "num_photos": len(photos)
                })
    return {"employees": employees, "total": len(employees)}


@app.delete("/employees/{employee_id}", tags=["Training Data"])
async def delete_employee(employee_id: str):
    """Remove an employee and all their training photos."""
    employee_dir = TRAINING_DIR / employee_id
    if not employee_dir.exists():
        raise HTTPException(status_code=404, detail=f"Employee {employee_id} not found")
    shutil.rmtree(employee_dir)
    return {
        "status": "success",
        "message": f"Employee {employee_id} and all photos deleted",
        "timestamp": datetime.now().isoformat()
    }


@app.post("/train", tags=["Model Training"])
async def train_model():
    """Train the facial recognition model on all uploaded employee photos."""
    global face_model, label_encoder, known_encodings_data

    all_encodings = []
    all_labels = []
    employee_metadata = {}
    errors = []

    if not TRAINING_DIR.exists() or not any(TRAINING_DIR.iterdir()):
        raise HTTPException(
            status_code=400,
            detail="No training data found. Upload employee photos first."
        )

    employee_dirs = [d for d in TRAINING_DIR.iterdir() if d.is_dir()]

    if len(employee_dirs) < 2:
        raise HTTPException(
            status_code=400,
            detail="At least 2 employees are required for training. Currently have: "
                   f"{len(employee_dirs)}"
        )

    for employee_dir in employee_dirs:
        employee_id = employee_dir.name
        meta_path = employee_dir / "metadata.json"
        metadata = {}
        if meta_path.exists():
            with open(meta_path, "r") as f:
                metadata = json.load(f)
        employee_metadata[employee_id] = metadata

        photo_files = [f for f in employee_dir.iterdir()
                       if f.is_file() and f.name != "metadata.json"]

        if not photo_files:
            errors.append(f"No photos found for employee {employee_id}")
            continue

        for photo_path in photo_files:
            try:
                image = face_recognition.load_image_file(str(photo_path))
                encodings = face_recognition.face_encodings(image)
                if encodings:
                    all_encodings.append(encodings[0])
                    all_labels.append(employee_id)
                else:
                    errors.append(f"No face found in {photo_path.name} for {employee_id}")
            except Exception as e:
                errors.append(f"Error processing {photo_path.name} for {employee_id}: {str(e)}")

    if len(all_encodings) < 2:
        raise HTTPException(
            status_code=400,
            detail="Not enough valid face encodings for training. Need at least 2."
        )

    unique_labels = set(all_labels)
    if len(unique_labels) < 2:
        raise HTTPException(
            status_code=400,
            detail="Need face encodings from at least 2 different employees for training."
        )

    X = np.array(all_encodings)
    label_encoder = LabelEncoder()
    y = label_encoder.fit_transform(all_labels)

    base_svm = SVC(kernel="rbf", probability=False, C=10.0, gamma="scale")
    face_model = CalibratedClassifierCV(base_svm, cv=min(3, min(
        np.bincount(y)
    )), method="sigmoid")
    face_model.fit(X, y)

    known_encodings_data = {
        "encodings": all_encodings,
        "labels": all_labels,
        "metadata": employee_metadata
    }

    with open(MODEL_PATH, "wb") as f:
        pickle.dump(face_model, f)
    with open(ENCODER_PATH, "wb") as f:
        pickle.dump(label_encoder, f)
    with open(ENCODINGS_PATH, "wb") as f:
        pickle.dump(known_encodings_data, f)

    logger.info(f"Model trained with {len(all_encodings)} encodings from {len(unique_labels)} employees")

    return TrainingStatus(
        status="success",
        num_employees=len(unique_labels),
        num_images=len(all_encodings),
        employees=list(unique_labels),
        timestamp=datetime.now().isoformat()
    )


@app.post("/recognize", tags=["Recognition"])
async def recognize_face(
    file: UploadFile = File(...),
    threshold: float = 0.5
):
    """
    Recognize faces in an uploaded image.
    Returns detailed probability distribution over all known employees for each detected face.
    
    - **file**: Image file containing one or more faces
    - **threshold**: Minimum confidence threshold for a positive identification (0.0-1.0)
    """
    global face_model, label_encoder, known_encodings_data

    if face_model is None or label_encoder is None:
        if not load_model():
            raise HTTPException(
                status_code=400,
                detail="No trained model found. Please train the model first using /train endpoint."
            )

    if not file.content_type or not file.content_type.startswith("image/"):
        raise HTTPException(status_code=400, detail="File must be an image")

    temp_path = Path("temp_recognition.jpg")
    try:
        content = await file.read()
        with open(temp_path, "wb") as f:
            f.write(content)

        image = face_recognition.load_image_file(str(temp_path))
        face_locations = face_recognition.face_locations(image)
        face_encodings = face_recognition.face_encodings(image, face_locations)

        if not face_encodings:
            return RecognitionResult(
                status="no_faces_detected",
                num_faces_detected=0,
                results=[],
                timestamp=datetime.now().isoformat()
            )

        results = []
        class_names = label_encoder.classes_

        for idx, (face_encoding, face_location) in enumerate(zip(face_encodings, face_locations)):
            encoding_array = np.array(face_encoding).reshape(1, -1)
            probabilities = face_model.predict_proba(encoding_array)[0]

            probability_distribution = {}
            for class_name, prob in zip(class_names, probabilities):
                metadata = known_encodings_data.get("metadata", {}).get(class_name, {})
                display_name = metadata.get("name", class_name)
                probability_distribution[class_name] = {
                    "employee_id": class_name,
                    "name": display_name,
                    "confidence": round(float(prob), 6),
                    "confidence_percentage": round(float(prob) * 100, 2)
                }

            sorted_distribution = dict(
                sorted(
                    probability_distribution.items(),
                    key=lambda x: x[1]["confidence"],
                    reverse=True
                )
            )

            best_match_id = class_names[np.argmax(probabilities)]
            best_confidence = float(np.max(probabilities))

            known_face_distances = face_recognition.face_distance(
                np.array(known_encodings_data["encodings"]),
                face_encoding
            )

            per_employee_distances = {}
            for label, distance in zip(known_encodings_data["labels"], known_face_distances):
                if label not in per_employee_distances:
                    per_employee_distances[label] = []
                per_employee_distances[label].append(float(distance))

            distance_metrics = {}
            for emp_id, distances in per_employee_distances.items():
                distance_metrics[emp_id] = {
                    "min_distance": round(min(distances), 6),
                    "mean_distance": round(np.mean(distances), 6),
                    "max_distance": round(max(distances), 6),
                    "num_reference_photos": len(distances)
                }

            best_metadata = known_encodings_data.get("metadata", {}).get(best_match_id, {})
            best_display_name = best_metadata.get("name", best_match_id)

            is_identified = best_confidence >= threshold

            top, right, bottom, left = face_location

            face_result = {
                "face_index": idx,
                "face_location": {
                    "top": top,
                    "right": right,
                    "bottom": bottom,
                    "left": left
                },
                "identification": {
                    "is_identified": is_identified,
                    "best_match": {
                        "employee_id": best_match_id,
                        "name": best_display_name,
                        "confidence": round(best_confidence, 6),
                        "confidence_percentage": round(best_confidence * 100, 2)
                    },
                    "threshold_used": threshold,
                    "verdict": "AUTHORIZED" if is_identified else "UNKNOWN"
                },
                "probability_distribution": sorted_distribution,
                "distance_metrics": distance_metrics,
                "entropy": round(float(-np.sum(
                    probabilities * np.log2(probabilities + 1e-10)
                )), 6),
                "top_n_matches": [
                    {
                        "rank": i + 1,
                        "employee_id": class_names[idx_sorted],
                        "name": known_encodings_data.get("metadata", {}).get(
                            class_names[idx_sorted], {}
                        ).get("name", class_names[idx_sorted]),
                        "confidence": round(float(probabilities[idx_sorted]), 6)
                    }
                    for i, idx_sorted in enumerate(np.argsort(probabilities)[::-1][:5])
                ]
            }

            results.append(face_result)

        return RecognitionResult(
            status="success",
            num_faces_detected=len(face_encodings),
            results=results,
            timestamp=datetime.now().isoformat()
        )

    finally:
        if temp_path.exists():
            os.remove(temp_path)


@app.post("/verify", tags=["Recognition"])
async def verify_employee(
    employee_id: str,
    file: UploadFile = File(...),
    threshold: float = 0.6
):
    """
    Verify if the face in the image matches a specific employee.
    Returns True/False along with confidence score.
    """
    global face_model, label_encoder, known_encodings_data

    if face_model is None or label_encoder is None:
        if not load_model():
            raise HTTPException(
                status_code=400,
                detail="No trained model found. Please train the model first."
            )

    if employee_id not in label_encoder.classes_:
        raise HTTPException(
            status_code=404,
            detail=f"Employee {employee_id} not found in trained model."
        )

    temp_path = Path("temp_verify.jpg")
    try:
        content = await file.read()
        with open(temp_path, "wb") as f:
            f.write(content)

        image = face_recognition.load_image_file(str(temp_path))
        face_encodings = face_recognition.face_encodings(image)

        if not face_encodings:
            raise HTTPException(status_code=400, detail="No face detected in the image")

        if len(face_encodings) > 1:
            raise HTTPException(
                status_code=400,
                detail="Multiple faces detected. Please provide an image with a single face."
            )

        encoding_array = np.array(face_encodings[0]).reshape(1, -1)
        probabilities = face_model.predict_proba(encoding_array)[0]

        class_names = list(label_encoder.classes_)
        employee_idx = class_names.index(employee_id)
        employee_confidence = float(probabilities[employee_idx])

        employee_encodings = [
            enc for enc, lbl in zip(
                known_encodings_data["encodings"],
                known_encodings_data["labels"]
            ) if lbl == employee_id
        ]
        distances = face_recognition.face_distance(
            np.array(employee_encodings), face_encodings[0]
        )

        metadata = known_encodings_data.get("metadata", {}).get(employee_id, {})
        display_name = metadata.get("name", employee_id)

        is_match = employee_confidence >= threshold

        return {
            "status": "success",
            "verification": {
                "employee_id": employee_id,
                "name": display_name,
                "is_match": is_match,
                "confidence": round(employee_confidence, 6),
                "confidence_percentage": round(employee_confidence * 100, 2),
                "threshold": threshold,
                "verdict": "VERIFIED" if is_match else "NOT VERIFIED"
            },
            "distance_metrics": {
                "min_distance": round(float(np.min(distances)), 6),
                "mean_distance": round(float(np.mean(distances)), 6),
                "max_distance": round(float(np.max(distances)), 6)
            },
            "full_probability_distribution": {
                class_names[i]: round(float(probabilities[i]), 6)
                for i in np.argsort(probabilities)[::-1]
            },
            "timestamp": datetime.now().isoformat()
        }

    finally:
        if temp_path.exists():
            os.remove(temp_path)


@app.get("/model/status", tags=["Model Management"])
async def model_status():
    """Get the current status of the trained model."""
    global face_model, label_encoder, known_encodings_data

    if face_model is None:
        load_model()

    if face_model is None:
        return {
            "status": "not_trained",
            "message": "No model has been trained yet.",
            "timestamp": datetime.now().isoformat()
        }

    return {
        "status": "ready",
        "num_classes": len(label_encoder.classes_),
        "classes": list(label_encoder.classes_),
        "num_training_encodings": len(known_encodings_data["encodings"]),
        "encodings_per_employee": {
            emp_id: known_encodings_data["labels"].count(emp_id)
            for emp_id in label_encoder.classes_
        },
        "model_file": str(MODEL_PATH),
        "model_file_exists": MODEL_PATH.exists(),
        "timestamp": datetime.now().isoformat()
    }


@app.post("/model/reset", tags=["Model Management"])
async def reset_model():
    """Reset the trained model (does not delete training photos)."""
    global face_model, label_encoder, known_encodings_data

    face_model = None
    label_encoder = None
    known_encodings_data = None

    for path in [MODEL_PATH, ENCODER_PATH, ENCODINGS_PATH]:
        if path.exists():
            os.remove(path)

    return {
        "status": "success",
        "message": "Model has been reset. Training data is preserved.",
        "timestamp": datetime.now().isoformat()
    }


@app.get("/health", tags=["System"])
async def health_check():
    """Health check endpoint for the security system."""
    model_ready = face_model is not None
    return {
        "status": "healthy",
        "model_loaded": model_ready,
        "num_employees_in_model": len(label_encoder.classes_) if label_encoder else 0,
        "timestamp": datetime.now().isoformat()
    }


